import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'outline' | 'dark';
  children: React.ReactNode;
  fullWidth?: boolean;
}

export const Button: React.FC<ButtonProps> = ({ 
  variant = 'primary', 
  children, 
  fullWidth = false, 
  className = '', 
  ...props 
}) => {
  const baseStyles = "inline-flex items-center justify-center px-8 py-4 text-base font-bold transition-all duration-300 transform rounded-lg focus:outline-none focus:ring-2 focus:ring-offset-2 disabled:opacity-50 disabled:cursor-not-allowed hover:-translate-y-1 shadow-lg";

  const variants = {
    primary: "bg-amber-500 hover:bg-amber-600 text-white shadow-amber-500/30 focus:ring-amber-500",
    secondary: "bg-slate-900 hover:bg-slate-800 text-white shadow-slate-900/30 focus:ring-slate-900",
    outline: "bg-transparent border-2 border-slate-900 text-slate-900 hover:bg-slate-50 focus:ring-slate-500",
    dark: "bg-slate-800 hover:bg-slate-700 text-white border border-slate-700"
  };

  const widthStyles = fullWidth ? "w-full" : "";

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${widthStyles} ${className}`} 
      {...props}
    >
      {children}
    </button>
  );
};

import React from 'react';

interface SectionTitleProps {
  title: string;
  subtitle?: string;
  align?: 'left' | 'center';
  light?: boolean;
}

export const SectionTitle: React.FC<SectionTitleProps> = ({ title, subtitle, align = 'center', light = false }) => {
  const alignment = align === 'center' ? 'text-center mx-auto' : 'text-left';
  const titleColor = light ? 'text-white' : 'text-slate-900';
  const subtitleColor = light ? 'text-slate-300' : 'text-slate-600';
  const barColor = light ? 'bg-amber-500' : 'bg-amber-500';

  return (
    <div className={`mb-16 max-w-3xl ${alignment}`}>
      <h2 className={`text-3xl md:text-4xl font-extrabold tracking-tight mb-4 ${titleColor}`}>
        {title}
      </h2>
      <div className={`h-1.5 w-24 rounded-full ${barColor} mb-6 ${align === 'center' ? 'mx-auto' : ''}`}></div>
      {subtitle && (
        <p className={`text-lg md:text-xl ${subtitleColor} leading-relaxed`}>
          {subtitle}
        </p>
      )}
    </div>
  );
};

